BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?imp ?impName ?importedPkgName WHERE {
  ?imp rdf:type vocab:package%20import .
  OPTIONAL { ?imp vocab:NamedElement_name ?impName . }
  ?imp vocab:PackageImport_importedPackage ?importedPkg .
  OPTIONAL { ?importedPkg vocab:NamedElement_name ?importedPkgName . }
  FILTER(
    CONTAINS(LCASE(STR(?importedPkgName)), "aps") ||
    CONTAINS(LCASE(STR(?importedPkg)), "aps")
  )
}
ORDER BY ?impName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?docName ?doc ?req ?reqName WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?reqName . }

  # Look for DOORS in any string metadata related to the requirement
  OPTIONAL { ?req vocab:Element_ownedElement+ ?meta . }
  OPTIONAL { ?req vocab:ownedComment+ ?c . }
  OPTIONAL { ?c rdf:type vocab:comment . }

  FILTER(
    EXISTS {
      ?s ?p ?o .
      BIND(?req AS ?s)
      FILTER(CONTAINS(LCASE(STR(?o)), "doors"))
    }
    || EXISTS {
      ?req ?p2 ?o2 .
      FILTER(CONTAINS(LCASE(STR(?o2)), "doors"))
    }
  )

  ?doc vocab:Element_ownedElement+ ?req .
  ?doc rdf:type vocab:document .
  OPTIONAL { ?doc vocab:NamedElement_name ?docName . }
}
ORDER BY ?docName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?docName ?doc ?req ?reqName WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?reqName . }

  # DOORS hint: requirement name or its owned comments mention DOORS
  FILTER(
    CONTAINS(LCASE(STR(?reqName)), "doors")
    || EXISTS { ?req vocab:ownedComment+ ?c . ?c rdf:type vocab:comment . FILTER(CONTAINS(LCASE(STR(?c)), "doors")) }
    || EXISTS { ?req vocab:ownedComment+ ?c2 . ?c2 vocab:body ?body . FILTER(CONTAINS(LCASE(STR(?body)), "doors")) }
  )

  ?doc rdf:type vocab:document .
  ?doc vocab:Element_ownedElement+ ?req .
  OPTIONAL { ?doc vocab:NamedElement_name ?docName . }
}
ORDER BY ?docName
LIMIT 25
